class Point:
    def __init__(self, x, y):
        self.x, self.y = x, y

    def __repr__(self):
        return f'Point({self.x}, {self.y})'  # eval-able

    def __str__(self):
        return f'({self.x}, {self.y})'       # human-readable

    def __eq__(self, other):
        if not isinstance(other, Point): return NotImplemented
        return self.x == other.x and self.y == other.y

    def __hash__(self):
        return hash((self.x, self.y))  # tuple hash — consistent with __eq__

    def __lt__(self, other):           # needed for heapq / sorted
        return (self.x, self.y) < (other.x, other.y)

    def __add__(self, other):          # enables: p1 + p2
        return Point(self.x + other.x, self.y + other.y)

    def __len__(self):
        return 2  # enables: len(point)

p1, p2 = Point(1, 2), Point(1, 2)
print(p1 == p2)          # True (via __eq__)
print({p1, p2})          # {Point(1, 2)} (uses __hash__)
print(sorted([p2, p1]))  # uses __lt__

class A:
    def who(self): return 'A'

class B(A):
    def who(self): return 'B'

class C(A):
    def who(self): return 'C'

class D(B, C):  # inherits from both B and C
    pass

print(D.mro())
# [D, B, C, A, object]
# D first, then left-to-right (B before C), A only once at the end

d = D()
print(d.who())  # 'B' — follows MRO order

# super() follows MRO — crucial in cooperative multiple inheritance
class LogMixin:
    def save(self):
        print('logging...')
        super().save()   # continues MRO chain, not just parent

class Model:
    def save(self):
        print('saving to db')

class LoggedModel(LogMixin, Model):
    pass

LoggedModel().save()
# logging...
# saving to db

from abc import ABC, abstractmethod
from typing import Protocol, runtime_checkable

# ABC — nominal subtyping (explicit inheritance)
class Shape(ABC):
    @abstractmethod
    def area(self) -> float: ...

    @abstractmethod
    def perimeter(self) -> float: ...

class Circle(Shape):
    def __init__(self, r): self.r = r
    def area(self): return 3.14159 * self.r ** 2
    def perimeter(self): return 2 * 3.14159 * self.r

# Shape()  # TypeError: Can't instantiate abstract class

# Protocol — structural subtyping (no inheritance required)
@runtime_checkable
class Drawable(Protocol):
    def draw(self) -> None: ...

class Button:             # does NOT inherit Drawable
    def draw(self): print('drawing button')

print(isinstance(Button(), Drawable))  # True — duck typing

# Use Protocol for type hints without coupling to a base class
def render(item: Drawable) -> None:
    item.draw()

# === Singleton (thread-safe via module-level) ===
import threading
class Singleton:
    _instance = None
    _lock = threading.Lock()
    def __new__(cls):
        if cls._instance is None:
            with cls._lock:           # double-checked locking
                if cls._instance is None:
                    cls._instance = super().__new__(cls)
        return cls._instance

# === Factory Method ===
class Animal: pass
class Dog(Animal):  pass
class Cat(Animal):  pass

def animal_factory(kind: str) -> Animal:
    registry = {'dog': Dog, 'cat': Cat}
    cls = registry.get(kind)
    if not cls: raise ValueError(f'Unknown animal: {kind}')
    return cls()  # open/closed principle: add to registry, not to if/elif

# === Observer ===
class EventBus:
    def __init__(self):
        self._listeners: dict[str, list] = {}

    def subscribe(self, event: str, callback):
        self._listeners.setdefault(event, []).append(callback)

    def publish(self, event: str, data=None):
        for cb in self._listeners.get(event, []):
            cb(data)

bus = EventBus()
bus.subscribe('user_signup', lambda u: print(f'Welcome email → {u}'))
bus.subscribe('user_signup', lambda u: print(f'Audit log → {u}'))
bus.publish('user_signup', 'alice@example.com')

import functools, time

# === Decorator with arguments ===
def retry(max_attempts=3, delay=0.5):
    def decorator(func):
        @functools.wraps(func)  # preserves __name__, __doc__
        def wrapper(*args, **kwargs):
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts - 1: raise
                    time.sleep(delay)
        return wrapper
    return decorator

@retry(max_attempts=3, delay=0.1)
def flaky_api_call():
    import random
    if random.random() < 0.7: raise ConnectionError('timeout')
    return 'success'

# === Context Manager via __enter__/__exit__ ===
class Timer:
    def __enter__(self):
        self.start = time.perf_counter()
        return self
    def __exit__(self, exc_type, exc_val, exc_tb):
        self.elapsed = time.perf_counter() - self.start
        return False  # don't suppress exceptions

with Timer() as t:
    sum(range(1_000_000))
print(f'{t.elapsed:.3f}s')

# === contextlib — one-liner context manager ===
from contextlib import contextmanager
@contextmanager
def managed_connection(url):
    conn = connect(url)  # setup
    try: yield conn
    finally: conn.close()  # always cleanup, even on exception
